css:
.wrapper {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  --shadow-rest: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  --glow: 0 0 24px -10px color-mix(in srgb, var(--accent) 55%, transparent);
  container-type: inline-size;
  height: 100%;
  max-width: 100%;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  font-variant-numeric: tabular-nums;
}

/* ---- chart card shell ---- */
.wrapper .crm-ticket-status {
  display: flex;
  flex-direction: column;
  height: 100%;
  max-width: 100%;
  box-sizing: border-box;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px;
  box-shadow: var(--shadow-rest);
  transition: border-color .16s ease, box-shadow .16s ease;
}
.wrapper .crm-ticket-status:hover {
  border-color: color-mix(in srgb, var(--accent) 35%, var(--line));
  box-shadow: var(--shadow-rest), var(--glow);
}
.wrapper .crm-ticket-status:focus-within {
  border-color: color-mix(in srgb, var(--accent) 45%, var(--line));
  box-shadow: var(--shadow-rest), var(--glow);
}

/* ---- header: accent dot + title + units sub ---- */
.wrapper .cts-head {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-bottom: 10px;
  min-width: 0;
}
.wrapper .cts-title {
  display: flex;
  align-items: center;
  gap: 9px;
  margin: 0;
  min-width: 0;
  font: 800 14px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  color: var(--ink);
  overflow-wrap: break-word;
}
.wrapper .cts-title::before {
  content: "";
  flex: none;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--accent);
}
.wrapper .cts-sub {
  margin: 0;
  min-width: 0;
  font: 500 11px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted);
  overflow-wrap: break-word;
}

/* ---- chart canvas (clickable: filters the page; min-height keeps the donut from collapsing) ---- */
.wrapper .cts-canvas {
  flex: 1;
  width: 100%;
  min-width: 0;
  min-height: 240px;
  cursor: pointer;
  border-radius: 10px;
}
.wrapper .cts-canvas:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

/* ---- empty state (Portal owns the loader; this is a calm 'no data' panel) ---- */
.wrapper .cts-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  min-height: 240px;
  padding: 16px;
  color: var(--muted);
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}
.wrapper .cts-empty[hidden] {
  display: none;
}

@media (prefers-reduced-motion: reduce) {
  .wrapper .crm-ticket-status { transition: none; }
}

/* ---- responsive: the block sizes to its own grid cell, not the viewport, so
   collapse against the block's width with container queries (declared via
   container-type on .wrapper), not @media. The donut's bottom legend wraps to
   extra rows as the cell narrows, so grow the canvas min-height in step to keep
   the legend from crowding the ring. ---- */
@container (max-width: 720px) {
  .wrapper .crm-ticket-status { padding: 14px; }
}
@container (max-width: 480px) {
  .wrapper .crm-ticket-status { padding: 13px; }
  .wrapper .cts-canvas,
  .wrapper .cts-empty { min-height: 260px; }
}
@container (max-width: 360px) {
  .wrapper .crm-ticket-status { padding: 12px; }
  .wrapper .cts-head { margin-bottom: 8px; }
  .wrapper .cts-canvas,
  .wrapper .cts-empty { min-height: 280px; }
}
